# Deobfuscated Code

After decoding all the base64 string table entries and resolving all references, here is the clean, deobfuscated code:

```javascript
// Constants
var TAU = 6.283;          // ≈ 2π
var PHI = 1.618;          // Golden ratio
var SQRT1_2 = 0.707;      // ≈ √(1/2)

// Simulation parameters
var config = {
  attractionRange: 4000,
  springCoeff: 0.004,
  amplification: 0.92,       // velocity damping factor
  centerGravity: 0.0003,
  streamMaxCount: 40,
  streamDecay: 0.04,
  theta: 0.06               // camera smoothing factor
};

// === NODES ===
var nodes = [
  { id: 'hub',       label: 'Hub',       r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha',     label: 'Alpha',     r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta',      label: 'Beta',      r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma',     label: 'Gamma',     r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta',     label: 'Delta',     r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon',   label: 'Epsilon',   r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// === EDGES (springs) ===
var edges = [
  { a: 'hub', b: 'alpha',   rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta',    rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta',   rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// === CAMERA ===
var camera       = { x: 400, y: 300, zoom: 1 };
var cameraTarget = { x: 400, y: 300, zoom: 1 };

// === PARTICLES ===
var particles = [];
var frameCount = 0;

// Find node by ID
function findNode(id) {
  for (var i = 0; i < nodes.length; i++) {
    if (nodes[i].id === id) return nodes[i];
  }
  return null;
}

// === PHYSICS STEP ===
function physicsStep() {
  // 1) Node-node repulsion (Coulomb-like)
  for (var i = 0; i < nodes.length; i++) {
    for (var j = i + 1; j < nodes.length; j++) {
      var dx = nodes[i].x - nodes[j].x;
      var dy = nodes[i].y - nodes[j].y;
      var dist = Math.sqrt(dx * dx + dy * dy) || 1;
      var force = config.attractionRange / (dist * dist);
      var fx = (dx / dist) * force;
      var fy = (dy / dist) * force;
      nodes[i].vx += fx;
      nodes[i].vy += fy;
      nodes[j].vx -= fx;
      nodes[j].vy -= fy;
    }
  }

  // 2) Spring forces along edges (Hooke's law)
  for (var e = 0; e < edges.length; e++) {
    var nodeA = findNode(edges[e].a);
    var nodeB = findNode(edges[e].b);
    if (!nodeA || !nodeB) continue;
    var dx = nodeB.x - nodeA.x;
    var dy = nodeB.y - nodeA.y;
    var dist = Math.sqrt(dx * dx + dy * dy) || 1;
    var displacement = dist - edges[e].rest;
    var force = (edges[e].k || config.springCoeff) * displacement;
    nodeA.vx += (dx / dist) * force;
    nodeA.vy += (dy / dist) * force;
    nodeB.vx -= (dx / dist) * force;
    nodeB.vy -= (dy / dist) * force;
  }

  // 3) Integration + centering gravity + velocity damping
  for (var n = 0; n < nodes.length; n++) {
    // Centering gravity toward (400, 300)
    nodes[n].vx += (400 - nodes[n].x) * config.centerGravity;
    nodes[n].vy += (300 - nodes[n].y) * config.centerGravity;
    // Damping
    nodes[n].vx *= config.amplification;
    nodes[n].vy *= config.amplification;
    // Position update
    nodes[n].x += nodes[n].vx;
    nodes[n].y += nodes[n].vy;
  }
}

// === SPAWN PARTICLE ===
function spawnParticle() {
  if (particles.length >= config.streamMaxCount) return;
  var sourceNode = nodes[Math.floor(Math.random() * nodes.length)];
  var angle = Math.random() * TAU;
  var speed = 0.3 + Math.random() * SQRT1_2;
  particles.push({
    x: sourceNode.x,
    y: sourceNode.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 800 + Math.random() * 1200,
    size: 0.8 + (Math.random() * PHI) * SQRT1_2
  });
}

// === UPDATE PARTICLES ===
function updateParticles() {
  for (var i = particles.length - 1; i >= 0; i--) {
    var p = particles[i];
    // Apply drag
    p.vx *= (1 - config.streamDecay * 0.125);
    p.vy *= (1 - config.streamDecay * 0.125);
    // Move
    p.x += p.vx;
    p.y += p.vy;
    // Age
    p.age++;
    // Remove if expired
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

// === SMOOTH CAMERA ===
function updateCamera() {
  camera.x    += (cameraTarget.x    - camera.x)    * config.theta;
  camera.y    += (cameraTarget.y    - camera.y)    * config.theta;
  camera.zoom += (cameraTarget.zoom - camera.zoom)  * config.theta;
}

// === MAIN LOOP ===
function tick() {
  physicsStep();
  updateParticles();
  updateCamera();
  if (frameCount % 3 === 0) spawnParticle();
  frameCount++;
}

setInterval(tick, 16);  // ~60 FPS
```

## Summary

This is a **force-directed graph simulation** with:

| Component | Algorithm |
|---|---|
| **Repulsion** | Coulomb's law — nodes repel each other inversely proportional to distance² |
| **Springs** | Hooke's law — edges pull/push nodes toward a rest length |
| **Centering** | Weak gravity pulls all nodes toward center point (400, 300) |
| **Damping** | Velocity multiplied by 0.92 each frame (energy dissipation) |
| **Particles** | Cosmetic stream particles emitted from random nodes, subject to drag and aging |
| **Camera** | Exponential smoothing (lerp) toward a target with factor `theta = 0.06` |

The string table contained misleading names (e.g., adversarial base64-encoded red herrings), but cross-checking against the actual algorithm confirms this is a standard **spring-electric force-directed layout** with decorative particle effects.
